// Express + Postgres — safe filter/sort parsing
const ALLOWED_FILTERS = ['status', 'authorId'];
const ALLOWED_SORT = ['createdAt', 'title', 'views'];

function parseQuery(query) {
  const filters = {};
  for (const key of ALLOWED_FILTERS) {
    if (query.filter?.[key]) filters[key] = query.filter[key];
  }

  const rawSort = query.sort ?? '-createdAt';
  const dir = rawSort.startsWith('-') ? 'DESC' : 'ASC';
  const col = rawSort.replace(/^-/, '');
  const sort = ALLOWED_SORT.includes(col) ? { col, dir } : { col: 'createdAt', dir: 'DESC' };

  return { filters, sort };
}

// Express.js REST endpoint with conditional request support
app.get('/api/articles/:id', async (req, res) => {
  const article = await db.articles.findById(req.params.id);
  if (!article) return res.status(404).end();

  const etag = `"${createHash('md5').update(JSON.stringify(article)).digest('hex')}"`;
  res.setHeader('ETag', etag);
  res.setHeader('Cache-Control', 'public, max-age=60, stale-while-revalidate=300');
  res.setHeader('Last-Modified', article.updatedAt.toUTCString());

  if (req.headers['if-none-match'] === etag) {
    return res.status(304).end();
  }

  res.json(article);
});

